import { Component } from '@angular/core';
import { Form, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { ApiService } from '@services/api.service';
import { ToastrService } from 'ngx-toastr';

@Component({
  selector: 'app-store-service-details',
  templateUrl: './store-service-details.component.html',
  styleUrls: ['./store-service-details.component.scss']
})
export class StoreServiceDetailsComponent {

  isLoading: boolean = false
  storeServiceChargeId: string;

  storeServiceChargeForm: FormGroup;

  storeServiceCharge: any;

  constructor(
    private api: ApiService, 
    private fb: FormBuilder, 
    private toastr: ToastrService,
    private route: ActivatedRoute,
    private router: Router
  ) {
    this.route.params.subscribe(params => {
      this.storeServiceChargeId = params.store_service_charge_id;
      this.getStoreServiceCharge()
    })

    this.storeServiceChargeForm = this.fb.group({
      service_charge_type: ['percentage', [Validators.required]],
      service_charge_value: [0, [Validators.required]]
    })

  }

  getStoreServiceCharge() {
    if(this.storeServiceChargeId) {
      const sub = this.api.getStoreServiceChargeDetails(this.storeServiceChargeId).subscribe((response: any) => {
        sub.unsubscribe()
        this.storeServiceCharge = response.store_service_charge;
        this.storeServiceChargeForm.setValue({
          service_charge_type: this.storeServiceCharge.service_charge_type,
          service_charge_value: this.storeServiceCharge.service_charge_value
        });
      })
    }else{
      const sub = this.api.getDefaultStoreServiceChargeDetails().subscribe((response: any) => {
        sub.unsubscribe()
        this.storeServiceCharge = response.store_service_charge;
        this.storeServiceChargeId = this.storeServiceCharge.store_service_charge_id;
        this.storeServiceChargeForm.setValue({
          service_charge_type: this.storeServiceCharge.service_charge_type,
          service_charge_value: this.storeServiceCharge.service_charge_value
        });
      })
    }
    
  }

  updateStoreServiceCharge() {
    const {service_charge_type, service_charge_value} = this.storeServiceChargeForm.value;
    const sub = this.api.updateStoreService(this.storeServiceChargeId, service_charge_type, service_charge_value).subscribe(
      (response: any) => {
        sub.unsubscribe();
        this.toastr.success(response.message)
        this.router.navigate(['/settings/storeservice'])
      }
    )
  }


  deleteStoreServiceCharge() {
    const sub = this.api.deleteStoreService(this.storeServiceChargeId).subscribe((response: any) => {
      sub.unsubscribe();
      this.toastr.success(response.message)
      this.router.navigate(['/settings/storeservice'])
    })
  }

}
