import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { ContactQueryComponent } from './contact-query/contact-query.component';
import { CreatestoreserviceComponent } from './createstoreservice/createstoreservice.component';
import { StoreServiceDetailsComponent } from './store-service-details/store-service-details.component';
import { StoreserviceComponent } from './storeservice/storeservice.component';
import { ViewContactQueryComponent } from './view-contact-query/view-contact-query.component';
import { OrderServiceChargeComponent } from './order-service-charge/order-service-charge.component';
import { OrderServiceComponent } from './order-service/order-service.component';
import { NotificationsComponent } from './notifications/notifications.component';
import { MembershipPlansComponent } from './membership-plans/membership-plans.component';
import { MebershipDetailsComponent } from './mebership-details/mebership-details.component';
import { TaxComponent } from './tax/tax.component';
import { RolesPermissionComponent } from './roles-permission/roles-permission.component';
import { RolesDetailsComponent } from './roles-details/roles-details.component';
const routes: Routes = [
  {path: 'storeservice', component: StoreserviceComponent},
  {path: 'viewstoreservice/default', component: StoreServiceDetailsComponent},
  {path: 'viewstoreservice/:store_service_charge_id', component: StoreServiceDetailsComponent},

  {path: 'createstoreservice', component: CreatestoreserviceComponent},
  {path: 'contactQuery',component:ContactQueryComponent},
  {path: 'contactQuery/:contact_query_id', component: ViewContactQueryComponent},

  {path: 'orderService', component: OrderServiceChargeComponent},
  
  {path: 'notifications', component: NotificationsComponent},

  {path: 'memberships', component: MembershipPlansComponent},
  {path: 'memberships/details/:membership_plan_id', component: MebershipDetailsComponent},

  {path: 'rolesPermission', component: RolesPermissionComponent},
  {path: 'rolesPermission/details/:default_role_id', component: RolesDetailsComponent},

  {path: 'tax', component: TaxComponent}

];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class SettingsRoutingModule { }
