import { Component } from '@angular/core';
import { FormGroup, FormBuilder, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { ApiService } from '@services/api.service';
import { ToastrService } from 'ngx-toastr';
import { catchError } from 'rxjs';

@Component({
  selector: 'app-view-contact-query',
  templateUrl: './view-contact-query.component.html',
  styleUrls: ['./view-contact-query.component.scss']
})
export class ViewContactQueryComponent {


  contactForm: FormGroup;
  isLoading: boolean = false;
  contactQueryId: string
  contactQuery: any;

  



  constructor(
    private api: ApiService, 
    private route: ActivatedRoute,
    private toastr: ToastrService,
    private fb: FormBuilder,
    private router: Router
    ){

      this.contactForm = this.fb.group({
        contact_query_id: ['', Validators.required],
        reply: ['', Validators.required]
      })

      this.route.params.subscribe((p) => {
        this.contactQueryId = p.contact_query_id;
        this.contactForm.controls.contact_query_id.setValue(this.contactQueryId)
        this.getContactQuery();

      })

  }

  ngOnInit() {
    
  }

  getContactQuery() {
    const sub = this.api.getContactQuery(this.contactQueryId).subscribe((response: any) => {
      sub.unsubscribe();
      this.contactQuery = response.contact_query;
    })
  }

  sendReply(reply) {
    const sub = this.api.sendContactQueryReply({contact_query_id: this.contactQueryId, reply})
    .pipe(
      catchError(err => {
        return err;
      })
    ).subscribe((response: any) => {
      sub.unsubscribe();
      if(response?.status >= 400) {
        this.toastr.error(response.error.message)
        return;
      }
      this.toastr.success(response.message);
      this.router.navigate(['/settings/contactQuery']);
    })
  }

}
