import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { ApiService } from '@services/api.service';
import { environment as env } from 'environments/environment';
import { ToastrService } from 'ngx-toastr';
import { catchError, debounceTime, tap } from 'rxjs';

@Component({
  selector: 'app-createstoreservice',
  templateUrl: './createstoreservice.component.html',
  styleUrls: ['./createstoreservice.component.scss']
})
export class CreatestoreserviceComponent {

  storeForm: FormGroup;
  storeServiceChargeForm: FormGroup;
  pageContent: string;
  isLoading = false;
  stores: Store[] = [];
  selectedStore: Store;
  storeId: string|null = null;


  constructor(
    private api: ApiService, 
    private route: ActivatedRoute,
    private toastr: ToastrService,
    private fb: FormBuilder,
    private router: Router
  ) {

    this.storeForm = this.fb.group({
      store_name: ['', [Validators.required]]
    })

    this.storeServiceChargeForm = this.fb.group({
      service_charge_type: ['percentage', [Validators.required]],
      service_charge_value: [0, [Validators.required]]
    })

    this.storeForm.valueChanges.pipe(
      debounceTime(100),
      tap(() => {
        this.listStores(this.storeForm.value.store_name);
      })
    ).subscribe();
    this.listStores(this.storeForm.value.store_name);
  }

  createStoreservice() {
    const store = this.storeForm.value;
    const {service_charge_type, service_charge_value} = this.storeServiceChargeForm.value;

    if(!this.storeId) {
      return alert("Please select store")
    }

    const sub = this.api.createStoreservice(
     this.storeId, service_charge_type, service_charge_value
    ).pipe(
      catchError(err => {
        return err;
      })
    ).subscribe((response: any) => {
      sub.unsubscribe();
      if(response?.status >= 400) {
        this.toastr.error(response.error.message)
        return;
      }
      this.toastr.success(response.message);
      this.router.navigate(['/settings/storeservice']);
    })
  }

  listStores(q: string) {
    const sub = this.api.listStores(q, 1, 100, 'store_id', 'DESC').subscribe((response: any) => {
      sub.unsubscribe()
   
      this.stores = response.stores.map(({store_name, store_id}) => {
        return {store_name, store_id}

      })
    })
  }

  changeStore(store: Store) {
    this.selectedStore = store; 
    this.storeId = store.store_id
  }


}


interface Store {
  store_id: string;
  store_name: string;
}