import { Component } from '@angular/core';
import { FormGroup, FormBuilder, Validators, FormArray } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { ApiService } from '@services/api.service';
import { ToastrService } from 'ngx-toastr';
import { catchError } from 'rxjs';

@Component({
  selector: 'app-roles-details',
  templateUrl: './roles-details.component.html',
  styleUrls: ['./roles-details.component.scss']
})
export class RolesDetailsComponent {
  isLoading: boolean = true
  defaultRoleId: string;
  membershipPlan : any;

  membershipPlanForm: FormGroup;

  roleName: string = "";
  defaultRoleForm: FormGroup;
  controllers: any[] = []

  constructor(
    private api: ApiService, 
    private fb: FormBuilder, 
    private toastr: ToastrService,
    private route: ActivatedRoute,
    private router: Router
  ) {

    this.route.params.subscribe((params) => {
      this.defaultRoleId = params.default_role_id;
      this.getAllControllers()
    })

  }

  getAllControllers() {
    this.api.listControllers().subscribe((data: any) => {
      const modules = data.modules;
      Array.from(modules).forEach((module: any) => {
        Array.from(module.controllers).forEach((controller: any) => {
          this.controllers.push({
            controller_id: controller.controller_id,
            controller_name: controller.controller_name,
            controller_key: controller.controller_key
          })
        })
      })

      this.defaultRoleForm = this.fb.group({
        default_role_id: [this.defaultRoleId, [Validators.required]],
        default_permissions: this.fb.array(
          this.controllers.map((controller) => {
            const fg = this.fb.group({
              controller_id: [controller.controller_id],
              controller_name: [controller.controller_name],
              value: [false]
            })
            controller.formGroup = fg;
            return fg;
          })
        )
      })
      console.log(this.defaultRoleForm)
      this.getRoleDetails();
    })
  }

  getRoleDetails() {
    this.api.getRoleDetails(this.defaultRoleId).subscribe((data: any) => {
      this.roleName = data.default_role.role_name;
      const defPermissions = this.defaultRoleForm.controls.default_permissions as FormArray
      Array.from(data.default_role.default_permissions).forEach(({controller_id}) => {
        const fg = defPermissions.controls.find((ct) => {
          return ct.value.controller_id == controller_id
        }) as FormGroup
        fg.controls.value.setValue(true)
      })
      this.isLoading = false;
    })
  }

  updateRole() {
    this.isLoading = true;
    const data = {
      default_role_id: this.defaultRoleId,
      default_permissions: this.defaultRoleForm.value.default_permissions.filter((dp: any) => dp.value).map((dp: any) => dp.controller_id)
    }
    const sub = this.api.updateDefaultRoles(data).
    pipe(
      catchError(err => {
        return err;
      })
    )
    .subscribe((response: any) => {
      this.isLoading = false;
      sub.unsubscribe();
      if(response?.status >= 400) {
        this.toastr.error(response.error.message)
        return;
      }
      this.toastr.success(response.message);
    })
  }

}
