import { Component, OnInit, ViewChild } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { MatPaginator } from '@angular/material/paginator';
import { MatSort } from '@angular/material/sort';
import { Page } from '@pages/page/page-list/page-list.component';
import { ApiService } from '@services/api.service';
import { tap, delay, merge, startWith, switchMap, map } from 'rxjs';

@Component({
  selector: 'app-contact-query',
  templateUrl: './contact-query.component.html',
  styleUrls: ['./contact-query.component.scss']
})
export class ContactQueryComponent {
  query: string = "";
  filterForm: FormGroup;
  isLoadingResults = true;

  displayedColumns: string[] = ['contact_query_id', 'name', 'email', 'subject','is_reply_sent',  'Action'];
  data : any[] = [];
  resultsLength = 0;
  sortBy: string = 'contact_query_id'


  @ViewChild(MatPaginator) paginator: MatPaginator;
  @ViewChild(MatSort) sort: MatSort;


  constructor(private api: ApiService, private fb: FormBuilder) {
    this.filterForm = this.fb.group({
      q: ['', [Validators.required]]
    })

    this.filterForm.valueChanges.pipe(
      tap(() => this.isLoadingResults = true),
      delay(1000)
    ).subscribe(() => {
      this.api.ContactQueryList(this.query, this.paginator.pageIndex+1, this.paginator.pageSize, this.sort.active, this.sort.direction).subscribe((data: any) => {
        this.isLoadingResults = false;
        // Flip flag to show that loading has finished.
        console.log(data);
        if (data === null) {
          return [];
        }

        this.resultsLength = data.total_count;
        this.data = data.contact_queries.map(cq => {
          return {
            contact_query_id: cq.contact_query_id,
            email: cq.email,
            name: cq.name,
            subject: cq.subject,
            is_reply_sent: cq.is_reply_sent
          }
        })
      })
    })
  }

  ngAfterViewInit() {
    this.sort.sortChange.subscribe(() => {
      this.paginator.pageIndex = 0
    });

    merge(this.sort.sortChange, this.paginator.page)
      .pipe(
        startWith({}),
        switchMap(() => {
          this.isLoadingResults = true;
          return this.api.ContactQueryList(this.query, this.paginator.pageIndex+1, this.paginator.pageSize, this.sort.active, this.sort.direction);
        }),
        map((data: any) => {
        console.log(data);

          this.isLoadingResults = false;
          // Flip flag to show that loading has finished.
          if (data === null) {
            return [];
          }

          this.resultsLength = data.total_count;
          return data.contact_queries.map(cq => {
            return {
              contact_query_id: cq.contact_query_id,
              email: cq.email,
              name: cq.name,
              subject: cq.subject,
              is_reply_sent: cq.is_reply_sent
            }
          })
          
        }),
      )
      .subscribe(data => this.data = data);

  }



}
