import { Component } from '@angular/core';
import { FormGroup, FormBuilder, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { ApiService } from '@services/api.service';
import { ToastrService } from 'ngx-toastr';
import { catchError } from 'rxjs';

@Component({
  selector: 'app-tax',
  templateUrl: './tax.component.html',
  styleUrls: ['./tax.component.scss']
})
export class TaxComponent {
  isLoading: boolean = true
  taxForm: FormGroup;

  constructor(
    private api: ApiService, 
    private fb: FormBuilder, 
    private toastr: ToastrService,
    private route: ActivatedRoute,
    private router: Router
  ) {

    this.taxForm = this.fb.group({
      tax_value: ['', [Validators.required, Validators.min(0), Validators.max(100)]],
      stripe_enabled_tax: [false, [Validators.required]],
      tax_type: ['percentage']
    })

    this.getTaxDetails()

  }

  
  getTaxDetails() {
    const sub = this.api.getDefaultTax().subscribe((response: any) => {
      sub.unsubscribe();
      this.isLoading = false;
      this.taxForm.setValue({
        tax_value: response.tax.tax_value,
        stripe_enabled_tax: response.tax.stripe_enabled_tax,
        tax_type: response.tax.tax_type,

      })
    })
  }


  updateTax() {
    this.isLoading = true;
    const sub = this.api.updateTax(this.taxForm.value)
    .pipe(
      catchError(err => err)
    )
    .subscribe((response: any) => {
      sub.unsubscribe()
      this.isLoading = false;
      if(response?.status >= 400) {
        this.toastr.error(response.error.message || response.message)
        return;
      }
      this.toastr.success(response.message)
    })
  }

}
