import {Component, ViewChild} from '@angular/core';
import { FormBuilder, FormControl, FormGroup, Validators } from '@angular/forms';
import {MatPaginator} from '@angular/material/paginator';
import { MatSort } from '@angular/material/sort';
import {MatTableDataSource} from '@angular/material/table';
import { ApiService } from '@services/api.service';
import { delay, map, merge, startWith, switchMap, tap } from 'rxjs';

@Component({
  selector: 'app-storeservice',
  templateUrl: './storeservice.component.html',
  styleUrls: ['./storeservice.component.scss']
})
export class StoreserviceComponent {

  query: string = "";
  filterForm: FormGroup;
  isLoadingResults = true;

  displayedColumns: string[] = ['store_service_charge_id', 'Store Name', 'Service Charge Value', 'Service Charge Type', 'Action'];
  data : Storeservice[] = [];
  resultsLength = 0;
  sortBy: string = 'store_service_charge_id'
  

  @ViewChild(MatPaginator) paginator: MatPaginator;
  @ViewChild(MatSort) sort: MatSort;


  constructor(private api: ApiService, private fb: FormBuilder) {
    this.filterForm = this.fb.group({
      q: ['', [Validators.required]]
    })

    this.filterForm.valueChanges.pipe(
      tap(() => this.isLoadingResults = true),
      delay(1000)
    ).subscribe(() => {
      this.api.listStoreservice(this.query, this.paginator.pageIndex+1, this.paginator.pageSize, this.sort.active, this.sort.direction).subscribe((data: any) => {
        this.isLoadingResults = false;
        // Flip flag to show that loading has finished.
        if (data === null) {
          return [];
        }

        this.resultsLength = data.total_count;
        this.data = data.store_service_charges.map(service => {
          return {
            store_service_charge_id: service.store_service_charge_id,
            store_name: service?.store?.store_name ? service?.store?.store_name : 'default',
            service_charge_value: service.service_charge_value,
            service_charge_type: service.service_charge_type,
          }
        })
      })
    })
  }

  ngAfterViewInit() {
    this.sort.sortChange.subscribe(() => {
      this.paginator.pageIndex = 0
    });

    merge(this.sort.sortChange, this.paginator.page)
      .pipe(
        startWith({}),
        switchMap(() => {
          this.isLoadingResults = true;
          return this.api.listStoreservice(this.query, this.paginator.pageIndex+1, this.paginator.pageSize, this.sort.active, this.sort.direction);
        }),
        map((data: any) => {
          this.isLoadingResults = false;
          // Flip flag to show that loading has finished.
          if (data === null) {
            return [];
          }

          this.resultsLength = data.total_count;
          return data.store_service_charges.map(service => {
            return {
              store_service_charge_id: service.store_service_charge_id,
              store_name: service?.store?.store_name ? service?.store?.store_name : 'default',
              service_charge_value: service.service_charge_value,
              service_charge_type: service.service_charge_type,
            }
          })
          
        }),
      )
      .subscribe(data => this.data = data);

  }

}

export interface Storeservice {
  store_service_charge_id: string;
  store_name: string | null;
  service_charge_value: number;
  service_charge_type: string;
}

