import { Component } from '@angular/core';
import { Form, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { ApiService } from '@services/api.service';
import { ToastrService } from 'ngx-toastr';
import { catchError } from 'rxjs';

@Component({
  selector: 'app-order-service-charge',
  templateUrl: './order-service-charge.component.html',
  styleUrls: ['./order-service-charge.component.scss']
})
export class OrderServiceChargeComponent {

  isLoading: boolean = true
  storeServiceChargeId: string;

  orderServiceChargeForm: FormGroup;

  constructor(
    private api: ApiService, 
    private fb: FormBuilder, 
    private toastr: ToastrService,
    private route: ActivatedRoute,
    private router: Router
  ) {

    this.orderServiceChargeForm = this.fb.group({
      service_charge_type: ['percentage', [Validators.required]],
      service_charge_value: [0, [Validators.required]]
    })

    this.getOrderServiceCharge()

  }

  getOrderServiceCharge() {
    const sub = this.api.getOrderStoreServiceChargeDetails().subscribe((response: any) => {
      sub.unsubscribe()
      this.isLoading = false
      this.orderServiceChargeForm.setValue({
        service_charge_type: response.service_charge_type,
        service_charge_value: response.service_charge_value
      });
    })
    
  }

  updateStoreServiceCharge() {
    const sub = this.api.updateOrderServiceCharge(this.orderServiceChargeForm.value.service_charge_type, this.orderServiceChargeForm.value.service_charge_value).
    pipe(
      catchError(err => {
        return err;
      })
    )
    .subscribe((response: any) => {
      sub.unsubscribe();
      if(response?.status >= 400) {
        this.toastr.error(response.error.message)
        return;
      }
      this.toastr.success(response.message);
    })
  }


}
